        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for(int i=0;i<T;i++){
            long X = Long.parseLong(br.readLine().trim());
            int r = (int)(X % 4);
            if(r==0) sb.append("North\n");
            else if(r==1) sb.append("East\n");
            else if(r==2) sb.append("South\n");
            else sb.append("West\n");
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t+1):
        x = int(data[i])
        r = x % 4
        if r == 0:
            out.append('North')
        elif r == 1:
            out.append('East')
        elif r == 2:
            out.append('South')
        else:
            out.append('West')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

